class Solution {
public:
    int maxProfit(vector<int>& prices) {
        int inf = 1e9;
        int minprice = inf, maxprofit = 0;
        for (int price: prices) {
            maxprofit = max(maxprofit, price - minprice); // 假设在历史最低点买入、今天卖出
            minprice = min(price, minprice); // 维护到今天为止的历史最低价
        }
        return maxprofit;
    }
};
